import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type CommitState = {
  commits: CommitEntry[]
  latestSha: string | null
}

type CommitDelta = {
  newCommits: CommitEntry[]
  count: number
}

const parseGitLog = (raw: string): CommitEntry[] => {
  if (!raw.trim()) return []
  return raw
    .trim()
    .split('\n')
    .map((line) => {
      const [sha, author, date, ...messageParts] = line.split('|')
      return { sha, author, date, message: messageParts.join('|') }
    })
}

export const gitCommitSensor: SensorFactory = {
  name: 'git-commit',
  snapshotPath: 'git-commit.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    const proc = Bun.spawn(
      ['git', 'log', 'origin/main', '--format=%H|%an|%aI|%s', '-n', '50'],
      { stdout: 'pipe', stderr: 'pipe' },
    )

    const output = await new Response(proc.stdout).text()
    const commits = parseGitLog(output)

    // Fetch latest remote state before reading
    if (!signal.aborted) {
      Bun.spawn(['git', 'fetch', 'origin', 'main', '--quiet'], {
        stdout: 'ignore',
        stderr: 'ignore',
      })
    }

    return {
      commits,
      latestSha: commits[0]?.sha ?? null,
    } satisfies CommitState
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as CommitState

    // First run — report initial state only if there are commits
    if (!previous) {
      return curr.commits.length > 0
        ? ({ newCommits: curr.commits.slice(0, 5), count: curr.commits.length } satisfies CommitDelta)
        : null
    }

    const prev = previous.data as CommitState
    if (curr.latestSha === prev.latestSha) return null

    // Find commits newer than the previous latest SHA
    const prevShaSet = new Set(prev.commits.map((c) => c.sha))
    const newCommits = curr.commits.filter((c) => !prevShaSet.has(c.sha))

    if (newCommits.length === 0) return null

    return {
      newCommits,
      count: newCommits.length,
    } satisfies CommitDelta
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type CommitDelta = {
  newCommits: CommitEntry[]
  count: number
}

const WS_URL = process.env.WS_ALERT_URL ?? 'ws://localhost:8080'

const formatCommitAlert = (delta: CommitDelta): string => {
  const header = `🔔 ${delta.count} new commit${delta.count === 1 ? '' : 's'} pushed to main:`
  const lines = delta.newCommits.map(
    (c) => `  ${c.sha.slice(0, 7)} — ${c.author}: ${c.message}`,
  )
  return [header, ...lines].join('\n')
}

let lastDelta: CommitDelta | null = null

const websocketHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return

    const wsUrl = process.env.WS_ALERT_URL ?? WS_URL
    try {
      const ws = new WebSocket(wsUrl)
      ws.addEventListener('open', () => {
        ws.send(JSON.stringify({
          type: 'git-commit-alert',
          content: msg.content,
          timestamp: new Date().toISOString(),
        }))
        ws.close()
      })
      ws.addEventListener('error', () => {
        /* non-fatal — sensor keeps running */
      })
    } catch {
      /* non-fatal */
    }
  },
}

export const gitCommitGoal = createGoal((_trigger) => ({
  threads: {
    'git-commit-watch': bThread(
      [
        // Step 1: Wait for a sensor delta from the git-commit sensor
        bSync({
          waitFor: ({ type, detail }) => {
            if (type !== AGENT_EVENTS.sensor_delta) return false
            const d = detail as SensorDeltaDetail
            if (d.sensor !== 'git-commit') return false
            lastDelta = d.delta as CommitDelta
            return true
          },
        }),
        // Step 2: Request a task so the agent can compose and send the alert
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'New commits detected on main branch.',
                lastDelta ? formatCommitAlert(lastDelta) : '',
                'Send a WebSocket alert summarizing the new commits.',
              ].join('\n'),
            },
          },
        }),
      ],
      true, // repeat — continuously watch for new pushes
    ),
  },
  handlers: websocketHandler,
}))

