import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type PdfEntry = {
  path: string
  modifiedMs: number
}

type PdfState = {
  files: PdfEntry[]
}

type PdfDelta = {
  newFiles: PdfEntry[]
}

export const pdfSensor: SensorFactory = {
  name: 'pdf-sensor',
  snapshotPath: 'pdf-sensor.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const dir = `${process.env.HOME}/Documents`
    const entries: PdfEntry[] = []

    for await (const entry of new Bun.Glob('**/*.pdf').scan({ cwd: dir, absolute: true })) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
      const file = Bun.file(entry)
      entries.push({
        path: entry,
        modifiedMs: file.lastModified,
      })
    }

    return { files: entries } satisfies PdfState
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as PdfState

    if (!previous) {
      return curr.files.length > 0 ? { newFiles: curr.files } satisfies PdfDelta : null
    }

    const prev = previous.data as PdfState
    const previousPaths = new Set(prev.files.map((f) => f.path))
    const newFiles = curr.files.filter((f) => !previousPaths.has(f.path))

    return newFiles.length > 0 ? { newFiles } satisfies PdfDelta : null
  },
}

