import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type HealthStatus = {
  statusCode: number
  ok: boolean
  timestamp: string
}

export const healthSensor: SensorFactory = {
  name: 'http-health',
  snapshotPath: 'health.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const url = process.env.HEALTH_ENDPOINT_URL ?? 'https://api.example.com/health'
    try {
      const response = await fetch(url, { signal })
      return {
        statusCode: response.status,
        ok: response.ok,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    } catch (error) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
      return {
        statusCode: 0,
        ok: false,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as HealthStatus

    if (!previous) {
      return curr.ok ? null : curr
    }

    const prev = previous.data as HealthStatus

    if (curr.statusCode === prev.statusCode) return null

    return {
      previousStatusCode: prev.statusCode,
      currentStatusCode: curr.statusCode,
      ok: curr.ok,
      timestamp: curr.timestamp,
    }
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type HealthDelta = {
  previousStatusCode: number
  currentStatusCode: number
  ok: boolean
  timestamp: string
}

const isNon200HealthDelta = ({ type, detail }: { type: string; detail: unknown }): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const sensorDetail = detail as SensorDeltaDetail
  if (sensorDetail.sensor !== 'http-health') return false
  const delta = sensorDetail.delta as HealthDelta
  return !delta.ok
}

const notificationHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return
    const webhookUrl = process.env.DISCORD_WEBHOOK_URL
    if (!webhookUrl) return
    fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: msg.content }),
    }).catch(() => {/* non-fatal */})
  },
}

export const healthAlertGoal = createGoal((_trigger) => ({
  threads: {
    'health-alert': bThread(
      [
        bSync({
          waitFor: isNon200HealthDelta,
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'The HTTP health check detected a non-200 status code. ' +
                'Compose an alert message describing the outage and send it via the proactive notification channel.',
            },
          },
        }),
      ],
      true,
    ),
  },
  handlers: notificationHandler,
}))

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type AccumulatedDelta = {
  sensor: string
  delta: unknown
  timestamp: string
}

const SMTP_RELAY_URL = process.env.SMTP_RELAY_URL ?? ''
const DIGEST_RECIPIENT = process.env.DIGEST_RECIPIENT ?? ''
const DIGEST_FROM = process.env.DIGEST_FROM ?? 'agent@proactive.local'

let collectedDeltas: AccumulatedDelta[] = []

const formatDigestHtml = (deltas: AccumulatedDelta[]): string => {
  if (deltas.length === 0) {
    return '<p>No sensor changes detected in the past 24 hours.</p>'
  }

  const rows = deltas
    .map(
      (d) =>
        `<tr>
          <td>${d.sensor}</td>
          <td>${d.timestamp}</td>
          <td><pre>${JSON.stringify(d.delta, null, 2)}</pre></td>
        </tr>`,
    )
    .join('\n')

  return `<h2>Daily Sensor Digest</h2>
<p>${deltas.length} change(s) detected in the past 24 hours.</p>
<table border="1" cellpadding="6" cellspacing="0">
  <thead>
    <tr><th>Sensor</th><th>Timestamp</th><th>Delta</th></tr>
  </thead>
  <tbody>${rows}</tbody>
</table>`
}

const digestHandlers: DefaultHandlers = {
  // Accumulate every sensor delta into the collection buffer
  [AGENT_EVENTS.sensor_delta]: ({ detail }) => {
    const { sensor, delta } = detail as SensorDeltaDetail
    collectedDeltas.push({
      sensor,
      delta,
      timestamp: new Date().toISOString(),
    })
  },

  // When the agent produces a proactive message, drain the buffer and POST to SMTP relay
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return

    const pending = collectedDeltas.splice(0)
    const html = formatDigestHtml(pending)

    if (!SMTP_RELAY_URL || !DIGEST_RECIPIENT) return

    fetch(SMTP_RELAY_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        from: DIGEST_FROM,
        to: DIGEST_RECIPIENT,
        subject: `Daily Sensor Digest — ${new Date().toLocaleDateString('en-US', {
          weekday: 'long',
          year: 'numeric',
          month: 'long',
          day: 'numeric',
        })}`,
        html,
      }),
    }).catch(() => {
      // SMTP relay failure is non-fatal; deltas already drained
    })
  },
}

export const dailyDigestGoal = createGoal((_trigger) => ({
  threads: {
    'daily-digest': bThread(
      [
        // Step 1: Wait for at least one sensor delta to arrive
        bSync({
          waitFor: ({ type }) => type === AGENT_EVENTS.sensor_delta,
        }),
        // Step 2: Gate on 8 AM — the handler keeps accumulating deltas in the meantime
        bSync({
          waitFor: ({ type }) =>
            type === AGENT_EVENTS.tick && new Date().getHours() === 8,
        }),
        // Step 3: Request the agent to compose and send the digest
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'Compose and send a daily digest email summarizing all sensor changes collected over the past 24 hours. Format the digest clearly with sensor names, timestamps, and change details.',
            },
          },
        }),
      ],
      true, // repeat: restart cycle after each digest is sent
    ),
  },
  handlers: digestHandlers,
}))

import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type BackendStatus = {
  backend: 'local' | 'cloud'
  endpoint: string
  respondedAt: string | null
}

const LOCAL_INFERENCE_URL = process.env.LOCAL_INFERENCE_URL ?? 'http://localhost:11434'

export const inferenceBackendSensor: SensorFactory = {
  name: 'inference-backend',
  snapshotPath: 'inference-backend.json',

  async read(signal: AbortSignal): Promise<BackendStatus> {
    const healthUrl = `${LOCAL_INFERENCE_URL}/api/tags`
    try {
      const res = await fetch(healthUrl, {
        signal: AbortSignal.any([signal, AbortSignal.timeout(5_000)]),
      })
      if (res.ok) {
        return {
          backend: 'local',
          endpoint: LOCAL_INFERENCE_URL,
          respondedAt: new Date().toISOString(),
        }
      }
      return { backend: 'cloud', endpoint: LOCAL_INFERENCE_URL, respondedAt: null }
    } catch {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
      return { backend: 'cloud', endpoint: LOCAL_INFERENCE_URL, respondedAt: null }
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as BackendStatus
    if (!previous) return curr
    const prev = previous.data as BackendStatus
    return curr.backend !== prev.backend ? curr : null
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'

type BackendDelta = {
  backend: 'local' | 'cloud'
}

const HEARTBEAT_LOCAL_MS = 300_000
const HEARTBEAT_CLOUD_MS = 7_200_000

const isBackendDelta = (detail: unknown, target: 'local' | 'cloud'): boolean => {
  const d = detail as SensorDeltaDetail
  return d.sensor === 'inference-backend' && (d.delta as BackendDelta).backend === target
}

export const costAwareHeartbeatGoal = createGoal((_trigger) => ({
  threads: {
    'cloud-fallback': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta && isBackendDelta(detail, 'cloud'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Inference backend fell back to cloud API.',
                `Use set_heartbeat to change the monitoring interval to ${HEARTBEAT_CLOUD_MS}ms (2 hours) to conserve API costs.`,
              ].join(' '),
            },
          },
        }),
      ],
      true,
    ),
    'local-restore': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta && isBackendDelta(detail, 'local'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Local GPU inference restored.',
                `Use set_heartbeat to change the monitoring interval to ${HEARTBEAT_LOCAL_MS}ms (5 minutes) for aggressive monitoring.`,
              ].join(' '),
            },
          },
        }),
      ],
      true,
    ),
  },
}))

import { createAgentLoop } from 'src/agent/agent.loop.ts'
import { inferenceBackendSensor } from './sensor.ts'
import { costAwareHeartbeatGoal } from './goal.ts'

export const costAwareNode = createAgentLoop({
  proactive: {
    sensors: [inferenceBackendSensor],
    goals: [costAwareHeartbeatGoal],
    intervalMs: 300_000,
  },
})
